        dist_to_opp = abs(ox - nx) + abs(oy - ny)
        if best_move is None or dist_to_opp > best_gap:
            best_gap = dist_to_opp
            best_move = (dx, dy)
    if best_move is not None:
        return [best_move[0], best_move[1]]

    return [0, 0]
